import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;

import java.util.List;
import java.util.ArrayList;

/**
 * Generic Spoon transformation to fix Hibernate UserType nullSafeSet method signature
 * breaking change from SessionImplementor to SharedSessionContractImplementor
 */
public class Main {
    public static void main(String[] args) {
        // Create Spoon factory
        Factory factory = spoon.Launcher.createFactory();

        // Set the input directory (this can be parameterized)
        String inputPath = "/workspace/onebusaway-gtfs-modules";
        if (args.length > 0) {
            inputPath = args[0];
        }

        // Process the source files
        spoon.Launcher.run(new String[]{
            "--input", inputPath,
            "--output", "/tmp/transformed",
            "--level", "INFO",
            "--processors", HibernateUserTypeFixProcessor.class.getName()
        });
    }
}

class HibernateUserTypeFixProcessor extends spoon.reflect.visitor.CtScanner {

    @Override
    public <T> void scan(CtMethod<T> method) {
        // Look for methods named nullSafeSet in UserType implementations
        if (method.getSimpleName().equals("nullSafeSet")) {
            // Check if this method belongs to a class implementing UserType
            CtType<?> declaringType = method.getDeclaringType();

            if (declaringType != null) {
                // Check if the class implements UserType
                for (CtTypeReference<?> iface : declaringType.getSuperInterfaces()) {
                    if (isUserTypeInterface(iface)) {
                        // Check if the method has the wrong signature
                        List<CtParameter<?>> parameters = method.getParameters();
                        if (parameters.size() >= 4) {
                            CtParameter<?> lastParam = parameters.get(3);
                            if (isSessionImplementorType(lastParam.getType())) {
                                // Fix the method signature
                                fixNullSafeSetMethod(method, lastParam);
                            }
                        }
                    }
                }
            }
        }
        super.scan(method);
    }

    private boolean isUserTypeInterface(CtTypeReference<?> iface) {
        // Check if the interface is org.hibernate.usertype.UserType
        return "org.hibernate.usertype.UserType".equals(iface.getQualifiedName());
    }

    private boolean isSessionImplementorType(CtTypeReference<?> type) {
        // Check if the type is org.hibernate.engine.spi.SessionImplementor
        return "org.hibernate.engine.spi.SessionImplementor".equals(type.getQualifiedName()) ||
               "org.hibernate.engine.spi.SharedSessionContractImplementor".equals(type.getQualifiedName());
    }

    private void fixNullSafeSetMethod(CtMethod<?> method, CtParameter<?> oldParameter) {
        // Get the factory
        Factory factory = method.getFactory();

        // Create the new parameter with correct type
        CtTypeReference<?> newTypeRef = factory.Type().createReference("org.hibernate.engine.spi.SharedSessionContractImplementor");
        CtParameter<?> newParameter = factory.Core().createParameter()
                .setType(newTypeRef)
                .setSimpleName(oldParameter.getSimpleName())
                .setAnnotations(new ArrayList<>(oldParameter.getAnnotations()));

        // Replace the parameter
        List<CtParameter<?>> parameters = method.getParameters();
        int index = parameters.indexOf(oldParameter);
        if (index >= 0) {
            parameters.set(index, newParameter);
            method.setParameters(parameters);
        }
    }
}

